#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 1000
#define MAX_M 1000

int min_distance(char map[][MAX_M], int n, int m) {
    int chef_x, chef_y, spoon_x, spoon_y;
    int dx[] = {-1, -1, -1, 0, 0, 1, 1, 1};
    int dy[] = {-1, 0, 1, -1, 1, -1, 0, 1};
    int queue[n*m][2];
    int front, rear;
    int visited[n][m];
    int min_dist = n * m;
    int dist[n][m];

    // Find the location of The Chef and the golden spoon
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (map[i][j] == '@') {
                chef_x = i;
                chef_y = j;
            } else if (map[i][j] == '$') {
                spoon_x = i;
                spoon_y = j;
            }
        }
    }

    // Initialize the queue and visited array
    front = rear = 0;
    queue[rear][0] = chef_x;
    queue[rear][1] = chef_y;
    visited[chef_x][chef_y] = 1;
    dist[chef_x][chef_y] = 0;
    rear++;

    while (front < rear) {
        int x = queue[front][0];
        int y = queue[front][1];
        front++;

        // Check if we have reached the golden spoon
        if (x == spoon_x && y == spoon_y) {
            return dist[x][y];
        }

        // Explore neighboring cells
        for (int i = 0; i < 8; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // Check if the neighboring cell is within the map boundaries and not visited
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && !visited[nx][ny]) {
                // Mark the neighboring cell as visited and add it to the queue
                visited[nx][ny] = 1;
                dist[nx][ny] = dist[x][y] + 1;
                queue[rear][0] = nx;
                queue[rear][1] = ny;
                rear++;
            }
        }
    }

    return -1;
}

int main() {
    int n, m;
    char map[MAX_N][MAX_M];

    scanf("%d %d", &n, &m);

    for (int i = 0; i < n; i++) {
        scanf("%s", map[i]);
    }

    printf("%d\n", min_distance(map, n, m));

    return 0;
}

