import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        char[][] map = new char[n][m];

        for (int i = 0; i < n; i++) {
            String line = scanner.next();
            map[i] = line.toCharArray();
        }

        System.out.println(minDistance(map, n, m));
    }

    public static int minDistance(char[][] map, int n, int m) {
        int chefX = 0, chefY = 0, spoonX = 0, spoonY = 0;
        int[] dx = {-1, -1, -1, 0, 0, 1, 1, 1};
        int[] dy = {-1, 0, 1, -1, 1, -1, 0, 1};
        Queue<int[]> queue = new LinkedList<>();
        boolean[][] visited = new boolean[n][m];
        int[][] dist = new int[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                dist[i][j] = n * m;
            }
        }

        // Find the location of The Chef and the golden spoon
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (map[i][j] == '@') {
                    chefX = i;
                    chefY = j;
                } else if (map[i][j] == '$') {
                    spoonX = i;
                    spoonY = j;
                }
            }
        }

        // Initialize the queue and visited array
        queue.add(new int[] {chefX, chefY});
        visited[chefX][chefY] = true;
        dist[chefX][chefY] = 0;

        while (!queue.isEmpty()) {
            int[] current = queue.poll();
            int x = current[0];
            int y = current[1];

            // Check if we have reached the golden spoon
            if (x == spoonX && y == spoonY) {
                return dist[x][y];
            }

            // Explore neighboring cells
            for (int i = 0; i < 8; i++) {
                int nx = x + dx[i];
                int ny = y + dy[i];

                // Check if the neighboring cell is within the map boundaries and not visited
                if (nx >= 0 && nx < n && ny >= 0 && ny < m && !visited[nx][ny]) {
                    // Mark the neighboring cell as visited and add it to the queue
                    visited[nx][ny] = true;
                    dist[nx][ny] = dist[x][y] + 1;
                    queue.add(new int[] {nx, ny});
                }
            }
        }

        return -1;
    }
}

